// Calls Supabase Edge Function to compute H3 indexes
const SUPABASE_URL = 'https://nyiqzfpirtsozxvdnord.supabase.co';
const SERVICE_KEY = $env.SUPABASE_SERVICE_KEY ?? '';

const items = $input.all();
const results = [];

for (const item of items) {
  const { id, latitude, longitude, company_id } = item.json;
  if (!latitude || !longitude) continue;

  try {
    const res = await fetch(SUPABASE_URL + '/functions/v1/compute-h3', {
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + SERVICE_KEY,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ store_id: id, latitude, longitude }),
    });

    const data = await res.json();
    results.push({
      json: {
        store_id: id,
        company_id,
        latitude: parseFloat(latitude),
        longitude: parseFloat(longitude),
        h3_r5: data.h3_r5,
        h3_r7: data.h3_r7,
        h3_r9: data.h3_r9,
      }
    });
  } catch (e) {
    // Skip failed stores — they can be retried next run
    console.error(`H3 failed for ${id}: ${e.message}`);
  }
}

return results;

// Group stores by h3_r7 and compute whitespace / density per cell
const items = $input.all();
const cellMap = {};

for (const item of items) {
  const { h3_r7, company_id, avg_rating } = item.json;
  if (!h3_r7 || !company_id) continue;

  const key = `${h3_r7}::${company_id}`;
  if (!cellMap[key]) {
    cellMap[key] = {
      h3_index: h3_r7,
      resolution: 7,
      company_id,
      store_count: 0,
      ratings: [],
    };
  }

  cellMap[key].store_count++;
  if (avg_rating) cellMap[key].ratings.push(parseFloat(avg_rating));
}

return Object.values(cellMap).map(cell => {
  const avgRating = cell.ratings.length > 0
    ? cell.ratings.reduce((a, b) => a + b, 0) / cell.ratings.length
    : null;

  // Whitespace = inverse of density (scale 0-100)
  // High score = low competition = high opportunity
  const maxDensityPerCell = 20;
  const whitespaceScore = Math.max(0, Math.round(100 - (cell.store_count / maxDensityPerCell) * 100));

  return {
    json: {
      h3_index: cell.h3_index,
      resolution: cell.resolution,
      company_id: cell.company_id,
      store_count: cell.store_count,
      avg_rating: avgRating ? parseFloat(avgRating.toFixed(2)) : null,
      brand_penetration: {},
      category_mix: {},
      whitespace_score: whitespaceScore,
    }
  };
});
